# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request
from prometheus_client import start_http_server, Counter

app = Flask(__name__)

# Dictionary to store counters for each unique user-path combination
user_path_counters = {}

def get_user_path_counter(user_id, path):
    key = f"{user_id}:{path}"
    if key not in user_path_counters:
        user_path_counters[key] = Counter(f"http_requests_total_user_{user_id}_path_{path}", "Total HTTP requests", ['session_id'])
    return user_path_counters[key]

@app.route('/<path:path>')
def handle_request(path):
    user_id = request.headers.get('X-User-ID')
    session_id = request.headers.get('X-Session-ID')

    if not user_id or not session_id:
        return "Missing User ID or Session ID", 400

    counter = get_user_path_counter(user_id, path)
    counter.labels(session_id=session_id).inc()

    return f"Request received for {path} by user {user_id} with session {session_id}"

if __name__ == '__main__':
    start_http_server(8000)
    app.run(host='0.0.0.0', port=5000)